import { mapActions } from "vuex";
export default {
  props: {
    list: {
      type: Array,
      default: () => [],
    },
    type: {
      type: Number,
    },
    showMore: {
      type:   Boolean,
      default: false,
    },
  },
  data() {
    return {
      showTips: [],
      couponsList: [],
      id: "",
      isMore: false,
    };
  },
  methods: {
    ...mapActions(["getPublicData"]),
    onHandle(id) {
      this.id = id;
      const { type } = this;
      switch (type) {
        case 0:
          // 可使用
          break;
        case 1:
          break;
        // 使用
        case 2:
          break;
        //不可以用
        case 3:
          // 领券
          this.getCoupon();
          break;
        case 4:
          //使用
          if (this.selectId == id) {
            this.id = "";
          }
          this.$emit("use", this.id);
          this.selectId = this.id;
          break;
      }
    },
    async getCoupon() {
      const { msg, code } = await this.$post("coupon/getCoupon", {
        id: this.id,
      });
      if (code == 1) {
        this.$message({
          message: msg,
          type: "success",
        });
        this.getPublicData();
        this.$emit("reflash");
      }
    },
    onShowTips(index) {
      const { showTips } = this;

      this.showTips[index] = showTips[index] ? 0 : 1;
      // 拷贝数组
      this.showTips = Object.assign([], this.showTips);
    },
    changeShow() {
      this.isMore = !this.isMore
      this.list.forEach((item, index) => {
        item.isShow = true
        if(!this.isMore && index >= 4) {
          item.isShow = false
        }
      })
      this.couponsList = [...this.list]
    },
  },
  watch: {
    list: {
      handler: function (val) {
        if (val.length) {
          // 默认选中第一张
          if (this.type == 4) {
            this.id = val[0].id;
            this.selectId = this.id;
            this.$emit("use", this.id);
          }
        }
        let arr = val.map((item) => {
          return 0;
        });
        this.showTips = arr;
        this.list.forEach((item, index) => {
          item.isShow = true;
          if (this.showMore) {
            if (index >= 4) {
              item.isShow = false;
            }
          }
        });
        this.couponsList = this.list
      },
      immediate: true,
      deep: true,
    },
  },
};
